#include <iostream>

using namespace std;

int main()
{
    int day = 3;

    switch (day)
    {
        case 1:
            cout << "Monday";
            break;
        case 2:
            cout << "Tuesday";
            break;
        case 3:
            cout << "Wednesday";
            break;
        default:
            cout << "Invalid day";
    }

    return 0;
}

int day = 1;

switch (day)
{
    case 1:
        cout << "Monday";
        // missing break! falls through into case 2
    case 2:
        cout << "Tuesday";
        break;
}

int day = 6;

switch (day)
{
    case 6:
    case 7:
        cout << "Weekend";
        break;
    default:
        cout << "Weekday";
}

